Here's how to handle each scenario with modern MSTest (3.9+) attributes:

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;

[TestClass]
public sealed class MyTests
{
    // 1. Windows-only: skips on Linux/macOS
    [TestMethod]
    [OSCondition(OperatingSystems.Windows)]
    public void Registry_ReadsExpectedValue()
    {
        var value = Registry.GetValue(@"HKEY_LOCAL_MACHINE\SOFTWARE\...", "Key", null);
        Assert.IsNotNull(value);
    }

    // 2. Skip in CI (requires local GPU)
    [TestMethod]
    [CICondition(ConditionMode.Exclude)]
    public void RenderFrame_ProducesValidOutput()
    {
        var frame = GpuRenderer.RenderFrame();
        Assert.IsNotNull(frame);
    }

    // 3. Flaky external API — retry up to 3 times
    [TestMethod]
    [Retry(3)]
    public async Task WeatherApi_ReturnsForecast()
    {
        var forecast = await _weatherClient.GetForecastAsync();
        Assert.IsNotNull(forecast);
    }

    // 4. Cleanup temp files even on failure — use [TestCleanup]
    private string? _tempFile;

    [TestMethod]
    public void Export_WritesFile()
    {
        _tempFile = Path.GetTempFileName();
        Exporter.WriteTo(_tempFile);
        Assert.IsTrue(File.Exists(_tempFile));
    }

    [TestCleanup]
    public void Cleanup()
    {
        if (_tempFile is not null && File.Exists(_tempFile))
            File.Delete(_tempFile);
    }
}
```

**Key points:**

| Scenario | Attribute/Pattern | Since |
|---|---|---|
| OS-specific | `[OSCondition(OperatingSystems.Windows)]` | MSTest 3.10 |
| Skip in CI | `[CICondition(ConditionMode.Exclude)]` | MSTest 3.10 |
| Flaky retries | `[Retry(3)]` | MSTest 3.9 |
| Guaranteed cleanup | `[TestCleanup]` method | All versions |

- `[TestCleanup]` runs after **every** test, even on failure — use it for temp file deletion, connection disposal, etc.
- `[Retry]` should only mask genuine external flakiness, not bugs or race conditions.
- `[OSCondition]` / `[CICondition]` **skip** the test gracefully (not a failure) when the condition isn't met.
